    18→@Injectable()
    19→export class TicketService {
    20→  constructor(
    21→    private readonly txHost: TransactionHost<TransactionalAdapterTypeOrm>,
    22→  ) {}
    23→
    24→  async getOne(ticketId: string, userId: string) {
    25→    const ticketRepository = this.txHost.tx.getRepository(TicketEntity);
    26→
    27→    const ticket = await ticketRepository.findOne({
    28→      where: { id: ticketId, userId },
    29→      relations: ['attachedFiles'],
    30→    });
    31→
    32→    if (!ticket) {
    33→      throw new BadRequestException('Ticket not found');
    34→    }
    35→
    36→    return ticket;
    37→  }
    38→
    39→  async getMany(
    40→    userId: string,
    41→    listQuery: ListQuery,
    42→    filters?: {
    43→      search?: string;
    44→      statuses?: TicketStatus[];
    45→      categories?: TicketCategory[];
    46→    },
    47→  ) {
    48→    const ticketRepository = this.txHost.tx.getRepository(TicketEntity);
    49→
    50→    const query = ticketRepository
    51→      .createQueryBuilder('ticket')
    52→      .where('ticket.userId = :userId', { userId })
    53→      .select([
    54→        'ticket.id',
    55→        'ticket.subject',
    56→        'ticket.status',
    57→        'ticket.category',
    58→        'ticket.referenceId',
    59→        'ticket.createdAt',
    60→        'ticket.closedAt',
    61→      ]);
    62→
    63→    if (filters?.search) {
    64→      query.andWhere('ticket.subject ILIKE :search', {
    65→        search: `%${filters.search}%`,
    66→      });
    67→    }
    68→
    69→    if (filters?.statuses) {
    70→      query.andWhere('ticket.status IN (:...statuses)', {
    71→        statuses: filters.statuses,
    72→      });
    73→    }
    74→
    75→    if (filters?.categories) {
    76→      query.andWhere('ticket.category IN (:...categories)', {
    77→        categories: filters.categories,
    78→      });
    79→    }
    80→
    81→    const [data, total] = await query
    82→      .skip(listQuery.skip)
    83→      .take(listQuery.take)
    84→      .orderBy('ticket.createdAt', listQuery.order)
    85→      .getManyAndCount();
    86→
    87→    return {
    88→      total,
    89→      data,
    90→      skip: listQuery.skip,
    91→      take: listQuery.take,
    92→    };
    93→  }
    94→
    95→  async raise(
    96→    userId: string,
    97→    dto: {
    98→      subject: string;
    99→      description: string;
   100→      category: TicketCategory;
   101→      referenceId?: string;
   102→      attachedFileIds: string[];
   103→      preferredContactMethods: NotificationMedia[];
   104→    },
   105→  ) {
   106→    const ticketRepository = this.txHost.tx.getRepository(TicketEntity);
   107→
   108→    if (dto.referenceId) {
   109→      await this.validateReferenceId(dto.category, dto.referenceId, userId);
   110→    }
   111→
   112→    return ticketRepository.save({
   113→      userId,
   114→      subject: dto.subject,
   115→      description: dto.description,
   116→      category: dto.category,
   117→      referenceId: dto.referenceId,
   118→      attachedFiles: dto.attachedFileIds.map((id) => ({ id })),
   119→      preferredContactMethods: dto.preferredContactMethods,
   120→    });
   121→  }
   122→
   123→  async cancel(ticketId: string, userId: string) {
   124→    const ticketRepository = this.txHost.tx.getRepository(TicketEntity);
   125→    const ticket = await this.getOne(ticketId, userId);
   126→
   127→    if (ticket.status !== TicketStatus.Open) {
   128→      throw new BadRequestException('Ticket is not open');
   129→    }
   130→
   131→    return ticketRepository.save({
   132→      id: ticketId,
   133→      status: TicketStatus.Cancelled,
   134→      closedAt: new Date(),
   135→    });
   136→  }
   137→
   138→  private async validateReferenceId(
   139→    category: TicketCategory,
   140→    referenceId: string,
   141→    userId: string,
   142→  ) {
   143→    switch (category) {
   144→      case TicketCategory.BuybackRequest: {
   145→        const buybackRequestRepository =
   146→          this.txHost.tx.getRepository(BuybackRequestEntity);
   147→
   148→        const buybackRequest = await buybackRequestRepository.findOne({
   149→          where: { id: referenceId, buyback: { sellerId: userId } },
   150→        });
   151→
   152→        if (!buybackRequest) {
   153→          throw new BadRequestException('Buyback request not found');
   154→        }
   155→
   156→        break;
   157→      }
   158→      case TicketCategory.ActiveBuyback: {
   159→        const buybackRepository = this.txHost.tx.getRepository(BuybackEntity);
   160→
   161→        const buyback = await buybackRepository.findOne({
   162→          where: { id: referenceId, sellerId: userId },
   163→        });
   164→
   165→        if (!buyback) {
   166→          throw new BadRequestException('Buyback not found');
   167→        }
   168→
   169→        break;
   170→      }
   171→      case TicketCategory.Asset: {
   172→        const assetRepository = this.txHost.tx.getRepository(AssetEntity);
   173→
   174→        const asset = await assetRepository.findOne({
   175→          where: { id: referenceId, sellerId: userId },
   176→        });
   177→
   178→        if (!asset) {
   179→          throw new BadRequestException('Asset not found');
   180→        }
   181→        break;
   182→      }
   183→      case TicketCategory.Auction:
   184→        throw new BadRequestException('Auctions not supported yet');
   185→    }
   186→  }
   187→}
