    10→@Injectable()
    11→export class GuestTicketService {
    12→  constructor(
    13→    private readonly txHost: TransactionHost<TransactionalAdapterTypeOrm>,
    14→    private readonly emailNotificationService: EmailNotificationService,
    15→  ) {}
    16→
    17→  async create(dto: {
    18→    fullName: string;
    19→    email: string;
    20→    category: TicketCategory;
    21→    description: string;
    22→    attachedFileIds: string[];
    23→    preferredContactMethods: NotificationMedia[];
    24→  }) {
    25→    return this.txHost.withTransaction(async () => {
    26→      const ticketRepository = this.txHost.tx.getRepository(TicketEntity);
    27→      const fileRepository = this.txHost.tx.getRepository(FileEntity);
    28→
    29→      if (dto.attachedFileIds.length > 0) {
    30→        const files = await fileRepository.findBy(
    31→          dto.attachedFileIds.map((id) => ({ id })),
    32→        );
    33→
    34→        if (files.length !== dto.attachedFileIds.length) {
    35→          throw new BadRequestException('One or more attached files not found');
    36→        }
    37→
    38→        const invalidFiles = files.filter(
    39→          (f) => !f.path.startsWith('/guest-uploads/'),
    40→        );
    41→        if (invalidFiles.length > 0) {
    42→          throw new BadRequestException('Invalid file IDs provided');
    43→        }
    44→      }
    45→
    46→      const ticket = await ticketRepository.save({
    47→        userId: null,
    48→        isGuest: true,
    49→        guestName: dto.fullName,
    50→        guestEmail: dto.email,
    51→        subject: `Guest: ${dto.fullName}`,
    52→        description: dto.description,
    53→        category: dto.category,
    54→        attachedFiles: dto.attachedFileIds.map((id) => ({ id })),
    55→        preferredContactMethods: dto.preferredContactMethods,
    56→      });
    57→
    58→      await this.emailNotificationService.sendGuestTicketConfirmation({
    59→        to: dto.email,
    60→        guestName: dto.fullName,
    61→        ticketId: ticket.id,
    62→        category: dto.category,
    63→        description: dto.description,
    64→      });
    65→
    66→      return ticket;
    67→    });
    68→  }
    69→}
